using UnityEngine;

public class AnimationTransitions : MonoBehaviour
{
    private Animator animator;

    // Parameter names (must match the Animator)
    private readonly string SPEED = "Speed";
    private readonly string GROUNDED = "Grounded";
    private readonly string JUMP = "Jump";
    private readonly string ATTACK = "Attack";
    private readonly string DEATH = "Death";

    void Start()
    {
        animator = GetComponent<Animator>();
    }

    void Update()
    {
        if (animator == null) return;

        // Set Speed based on input
        float speed = Input.GetAxis("Horizontal");
        animator.SetFloat(SPEED, Mathf.Abs(speed));

        // Set Grounded (should be set by ground check)
        // animator.SetBool(GROUNDED, isGrounded);

        // Jump trigger
        if (Input.GetButtonDown("Jump"))
        {
            animator.SetTrigger(JUMP);
        }

        // Attack trigger
        if (Input.GetButtonDown("Fire1"))
        {
            animator.SetTrigger(ATTACK);
        }

        // Death trigger
        if (Input.GetKeyDown(KeyCode.K))
        {
            animator.SetTrigger(DEATH);
        }

        // Reset attack trigger (prevent holding)
        // Unity automatically resets triggers
    }

    // Example: Smooth transition between walking and running
    public void SetMovementSpeed(float speed)
    {
        if (animator != null)
        {
            animator.SetFloat(SPEED, speed);
        }
    }

    // Example: Set grounded state
    public void SetGrounded(bool grounded)
    {
        if (animator != null)
        {
            animator.SetBool(GROUNDED, grounded);
        }
    }

    // Example: Trigger jump
    public void TriggerJump()
    {
        if (animator != null)
        {
            animator.SetTrigger(JUMP);
        }
    }

    // Example: Trigger attack
    public void TriggerAttack()
    {
        if (animator != null)
        {
            animator.SetTrigger(ATTACK);
        }
    }

    // Example: Trigger death
    public void TriggerDeath()
    {
        if (animator != null)
        {
            animator.SetTrigger(DEATH);
        }
    }

    // Example: Check if currently in a transition
    public bool IsTransitioning()
    {
        if (animator != null)
        {
            return animator.IsInTransition(0);
        }
        return false;
    }
}

